Javascript.isReadOnly:
if (null != WP && null != WP.GetScreenProcess && null != WP.GetScreenProcess()) { 
				var localNumber = WPU.getValue("/params/param[@name='xml']/ds/Warrant/LocalNumber");
				if (localNumber == "" || localNumber == null) return true; }

Javascript.initialise:
var partyAgainstNumber = WPU.getValue("/params/param[@name='xml']/WarrantReturn/PartyAgainstNumber");
var def1Addr4 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant1/Address/Line[4]");
var def2Addr4 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant2/Address/Line[4]");
var partyAgainstAddr4 = "";
if(partyAgainstNumber == 1) {
	partyAgainstAddr4 = def1Addr4;
} else {
	partyAgainstAddr4 = def2Addr4; }
var otherPossessAddr4 = WPU.getValue("/params/param[@name='xml']/ds/ManageCase/OtherPossessionAddress/Address/Line[4]");
var possessAddr4 = "";
if(otherPossessAddr4 != "") {
	possessAddr4 = otherPossessAddr4;
} else {
	possessAddr4 = partyAgainstAddr4; }
Services.setValue(PossessAdLine4.dataBinding, possessAddr4);
